   464→      case "string": emitArg(Op.Const, addConst({ tag: "str", val: e.value })); break;
   465→      case "bool": emitArg(Op.Const, addConst({ tag: "bool", val: e.value })); break;
   466→      case "null": emitArg(Op.Const, addConst({ tag: "null" })); break;
   467→      case "ident": {
   468→        const local = resolveLocal(e.name);
   469→        if (local !== -1) { emitArg(Op.Load, local); break; }
   470→        const upval = resolveUpvalue(e.name);
   471→        if (upval !== -1) { emitArg(Op.LoadFree, upval); break; }
