   478→          const l = e.left.value, r = e.right.value;
   479→          let result: Value | null = null;
   480→          if (e.op === "+") result = { tag: "num", val: l + r };
   481→          else if (e.op === "-") result = { tag: "num", val: l - r };
   482→          else if (e.op === "*") result = { tag: "num", val: l * r };
   483→          else if (e.op === "/" && r !== 0) result = { tag: "num", val: l / r };
   484→          else if (e.op === "%") result = { tag: "num", val: l % r };
   485→          else if (e.op === "==") result = { tag: "bool", val: l === r };
   486→          else if (e.op === "!=") result = { tag: "bool", val: l !== r };
   487→          else if (e.op === "<") result = { tag: "bool", val: l < r };
   488→          else if (e.op === ">") result = { tag: "bool", val: l > r };
   489→          else if (e.op === "<=") result = { tag: "bool", val: l <= r };
   490→          else if (e.op === ">=") result = { tag: "bool", val: l >= r };
   491→          if (result) { emitArg(Op.Const, addConst(result)); break; }
   492→        }
   493→        // Phase 5.4: 상수 폴딩 - 문자열 + 문자열
   494→        if (e.left.kind === "string" && e.right.kind === "string" && e.op === "+") {
   495→          emitArg(Op.Const, addConst({ tag: "str", val: e.left.value + e.right.value }));
   496→          break;
   497→        }
   498→
   499→        // 두 피연산자 컴파일
   500→        compileExpr(e.left);
   501→        compileExpr(e.right);
   502→
   503→        // Phase 5.5: Typed Op 선택
   504→        const leftType = inferExprType(e.left);
   505→        const rightType = inferExprType(e.right);
   506→
   507→        // num + num → Typed Arithmetic
   508→        if (leftType === "num" && rightType === "num") {
   509→          const typedArith: Record<string, Op> = {
   510→            "+": Op.AddNum, "-": Op.SubNum, "*": Op.MulNum,
   511→            "/": Op.DivNum, "%": Op.ModNum,
