   180→  run(): { output: string[]; result: Value } {
   181→    while (this.ip < this.chunk.code.length) {
   182→      const op = this.chunk.code[this.ip++];
   183→      if (op === Op.Halt) {
   184→        return { output: this.output, result: this.stack.length > 0 ? this.peek() : { tag: "null" } };
   185→      }
   186→      try {
   187→        this.execOp(op);
   188→      } catch (e) {
   189→        // If error was caught by a try handler
   190→        if (e instanceof Error && e.message.startsWith("__FREELANG_ERROR_CAUGHT__")) {
   191→          // Continue from the new IP (which should point to catch handler or finally)
   192→          continue;
   193→        }
   194→        // Re-throw unhandled errors
   195→        throw e;
   196→      }
   197→    }
   198→    return { output: this.output, result: { tag: "null" } };
   199→  }
