   249→  /** Call a FreeLang fn or builtin Value from within a builtin (HOFs). */
   250→  callValue(callee: Value, args: Value[]): Value {
   251→    if (callee.tag === "builtin") {
   252→      return this.builtinFns[callee.name](args, this);
   253→    }
   254→    if (callee.tag === "fn") {
   255→      const savedIp = this.ip;
   256→      const targetFrameDepth = this.frames.length;
   257→
   258→      // Mimic Call opcode: push callee + args, push frame
   259→      this.stack.push(callee);
   260→      for (const a of args) this.stack.push(a);
   261→      this.frames.push({
   262→        retAddr: savedIp,
   263→        baseSlot: this.stack.length - args.length,
   264→        fn: callee.name,
   265→        upvalues: callee.freeVars,
   266→        capabilities: callee.capabilities || [],  // Phase 6: Pass capabilities
   267→        resourceLimits: (callee as any).resourceLimits || {},  // Phase 6.4
   268→        opCount: 0,  // Phase 6.4
   269→        ioCount: 0,  // Phase 6.4
   270→      });
   271→      this.ip = callee.addr;
   272→
   273→      // Execute until our frame is popped by Return
   274→      try {
   275→        while (this.frames.length > targetFrameDepth) {
   276→          const op = this.chunk.code[this.ip++];
   277→          this.execOp(op);
   278→        }
   279→      } catch (e) {
   280→        // Re-throw sentinel errors so try_call can catch them
   281→        if (e instanceof Error && e.message === "__FREELANG_ERROR_CAUGHT__") {
   282→          throw e;
   283→        }
   284→        // Re-throw other errors
   285→        throw e;
   286→      }
   287→      // Return handler pushed the result onto the stack and restored ip
   288→      return this.stack.pop()!;
   289→    }
   290→    throw new Error(`Cannot call ${callee.tag}`);
   291→  }
