   293→  /** Safe call for try_call builtin - captures errors as Value objects */
   294→  trySafeCall(callee: Value, args: Value[]): { ok: boolean; value?: Value; error?: Value } {
   295→    this.clearLastError();
   296→    this.inTryCall = true;
   297→
   298→    try {
   299→      if (callee.tag === "builtin") {
   300→        const retVal = this.builtinFns[callee.name](args, this);
   301→        return { ok: true, value: retVal };
   302→      }
   303→      if (callee.tag === "fn") {
   304→        const retVal = this.callValue(callee, args);
   305→        return { ok: true, value: retVal };
   306→      }
   307→      return { ok: false, error: { tag: "str", val: `Cannot call ${callee.tag}` } };
   308→    } catch (e) {
   309→      // Check if a FreeLang error occurred
   310→      if (e instanceof Error && e.message.startsWith("__FREELANG_ERROR_CAUGHT__")) {
   311→        // Return the last error that was caught
   312→        return { ok: false, error: this.lastError || { tag: "str", val: "Unknown error" } };
   313→      }
   314→      // Otherwise return string error
   315→      return { ok: false, error: { tag: "str", val: String(e) } };
   316→    } finally {
   317→      this.inTryCall = false;
   318→    }
   319→  }
