    29→import { TypeChecker } from "./type-checker"; // Phase 5.4: TypeChecker 주입
    30→
    31→/** Run FreeLang source code, return output lines */
    32→export function run(source: string, basePath?: string): string[] {
    33→  const tokens = lex(source);
    34→  const ast = parse(tokens);
    35→
    36→  // Phase 5.4: TypeChecker 주입 - 타입 검증 후 컴파일
    37→  const checker = new TypeChecker();
    38→  const typeResult = checker.check(ast);
    39→  if (!typeResult.success) {
    40→    return typeResult.errors.map(e => `[TypeError] ${e.message}`);
    41→  }
    42→
    43→  // Fast path: no imports → compile directly (zero overhead)
    44→  const hasImports = ast.stmts.some(s => s.kind === "import");
    45→  if (!hasImports && !ast.stmts.some(s => s.kind === "export")) {
    46→    // Phase 5.5: typeEnv 전달 (Typed Op 생성용)
    47→    const chunk = compile(ast, typeResult.success ? typeResult.types : undefined);
    48→    const vm = new VM(chunk);
    49→    return vm.run().output;
    50→  }
    51→
    52→  // Merge module stmts into a single AST
    53→  const allStmts: Stmt[] = [];
    54→  const base = basePath ?? process.cwd();
    55→
    56→  for (const s of ast.stmts) {
    57→    if (s.kind === "import") {
    58→      const mod = loadModuleStmts(s.path, base);
    59→      allStmts.push(...mod.stmts);
    60→
    61→      if (s.alias) {
    62→        // import "mod" as M → create object right after module stmts
    63→        allStmts.push({
    64→          kind: "let",
    65→          name: s.alias,
    66→          mutable: false,
    67→          init: {
    68→            kind: "object",
    69→            entries: mod.exportedNames.map(n => ({ key: n, value: { kind: "ident" as const, name: n } }))
    70→          }
    71→        });
    72→      }
    73→    } else if (s.kind === "export") {
    74→      allStmts.push(s.stmt);
    75→    } else {
    76→      allStmts.push(s);
    77→    }
    78→  }
    79→
    80→  // Phase 5.5: typeEnv 전달
    81→  const chunk = compile({ stmts: allStmts }, typeResult.success ? typeResult.types : undefined);
    82→  const vm = new VM(chunk);
    83→  return vm.run().output;
    84→}
    85→
    86→/** Run FreeLang source code with PC tracing for debugging */
    87→export function runWithTrace(source: string, basePath?: string): { output: string[]; trace: string[] } {
    88→  const tokens = lex(source);
    89→  const ast = parse(tokens);
    90→
    91→  // Phase 5.4: TypeChecker 주입
    92→  const checker = new TypeChecker();
    93→  const typeResult = checker.check(ast);
    94→  if (!typeResult.success) {
    95→    return { output: typeResult.errors.map(e => `[TypeError] ${e.message}`), trace: [] };
    96→  }
    97→
    98→  const hasImports = ast.stmts.some(s => s.kind === "import");
    99→  if (!hasImports && !ast.stmts.some(s => s.kind === "export")) {
   100→    // Phase 5.5: typeEnv 전달
   101→    const chunk = compile(ast, typeResult.success ? typeResult.types : undefined);
   102→    const vm = new VM(chunk);
   103→    vm.enableTrace();
   104→    const result = vm.run();
   105→    return { output: result.output, trace: vm.getTraceLogs() };
   106→  }
   107→
   108→  const allStmts: Stmt[] = [];
   109→  const base = basePath ?? process.cwd();
   110→
   111→  for (const s of ast.stmts) {
   112→    if (s.kind === "import") {
   113→      const mod = loadModuleStmts(s.path, base);
   114→      allStmts.push(...mod.stmts);
   115→    } else if (s.kind === "export") {
   116→      allStmts.push(s.stmt);
   117→    } else {
   118→      allStmts.push(s);
   119→    }
   120→  }
   121→
   122→  // Phase 5.5: typeEnv 전달
   123→  const chunk = compile({ stmts: allStmts }, typeResult.success ? typeResult.types : undefined);
   124→  const vm = new VM(chunk);
   125→  vm.enableTrace();
   126→  const result = vm.run();
   127→  return { output: result.output, trace: vm.getTraceLogs() };
   128→}
