## 4. `index.ts` 수정 내용

```typescript
// index.ts의 run() 함수 내 수정 (compile() 호출 이후)

import { PeepholeOptimizer } from "./peephole-optimizer";
import { DCEOptimizer } from "./dce-optimizer";

// 기존:
const chunk = compile(ast, typeResult.success ? typeResult.types : undefined);
const vm = new VM(chunk);

// 변경:
const rawChunk = compile(ast, typeResult.success ? typeResult.types : undefined);
const peepholeOptimizer = new PeepholeOptimizer();
const dceOptimizer = new DCEOptimizer();
const peepholedChunk = peepholeOptimizer.optimize(rawChunk);
const optimizedChunk = dceOptimizer.optimize(peepholedChunk);
const vm = new VM(optimizedChunk);
```

## 5. `vm.ts` 수정 내용

```typescript
// 생성자 파라미터 추가
import { RuntimeProfiler } from "./runtime-profiler";

constructor(
  private chunk: Chunk,
  initialGlobals?: Map<string, Value>,
  private profiler?: RuntimeProfiler  // 새로 추가
) { ... }

// execOp() 첫 줄에 추가 (기존 resource limit 체크 이전)
private execOp(op: number) {
  this.profiler?.recordOp(op as Op);  // 추가
  // ... 기존 코드
}

// Op.Call 처리 내 fn 분기에 추가
case Op.Call: {
  const callee = this.stack[...];
  if (callee.tag === "fn") {
    this.profiler?.recordCall(callee.name);  // 추가
    // ... 기존 프레임 push 코드
  }
}
```

