test("A-1: Not+Not 이중 부정 → 제거", () => {
  // "!(!true)"를 컴파일하면 Const(true) + Not + Not 생성
  // 최적화 후: Const(true) + Not + Not → Const(true)
  // (실제로 소스에서 이 패턴이 나오려면 unary 중첩이 필요)
  // 대신 바이트코드를 직접 조작하여 테스트
  const rawChunk: Chunk = {
    code: [Op.Const, 0, Op.Not, Op.Not, Op.Print, Op.Halt],
    constants: [{ tag: "bool", val: true }],
    lines: [1, 1, 1, 1, 1, 1],
  };
  const optimizer = new PeepholeOptimizer();
  const optimized = optimizer.optimize(rawChunk);
  // Not + Not 쌍이 제거되어 코드 길이 감소
  assert(optimized.code.length < rawChunk.code.length, "Not+Not 제거 후 코드 축소");
  assert(optimizer.getStats().removedCount >= 2, "2개 opcode 제거");
});
