**TEST B-1: Halt 이후 코드 제거**
```typescript
test("B-1: Halt 이후 dead code 제거", () => {
  // Halt 뒤에 명령어가 있으면 제거
  const rawChunk: Chunk = {
    code: [Op.Const, 0, Op.Print, Op.Halt, Op.Const, 1, Op.Print],
    //                              ↑ 여기서 종료  ↑ dead code
    constants: [{ tag: "num", val: 1 }, { tag: "num", val: 99 }],
    lines: new Array(7).fill(1),
  };
  const dce = new DCEOptimizer();
  const optimized = dce.optimize(rawChunk);
  assert(optimized.code.length < rawChunk.code.length, "Halt 뒤 dead code 제거");
  assert(!optimized.code.slice(4).includes(99), "dead constant 접근 제거");
  // 실행 결과: 1만 출력 (99는 도달 불가)
  const vm = new VM(optimized);
  const { output } = vm.run();
  assert(output.length === 1 && output[0] === "1", "도달 가능 코드만 실행");
});
```

