  const source = `
    fn factorial(n) {
      if (n <= 1) {
        return 1
      }
      return n * factorial(n - 1)
    }
    print(factorial(5))
  `;

  // 최적화 없는 실행
  const rawOutput = run(source);

  // 최적화 파이프라인 포함 실행 (run()이 내부적으로 최적화 적용)
