  const tokens = lex(source);
  const ast = parse(tokens);
  const chunk = compile(ast);
  const peephole = new PeepholeOptimizer();
  const dce = new DCEOptimizer();
  const profiler = new RuntimeProfiler({ hotThreshold: 4 });
